package federation

import (
	"bytes"
	"context"
	"crypto/rand"
	"crypto/tls"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"math/big"
	"net/http"
	"net/url"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"time"
)

// DefaultHeartbeatInterval is the nominal heartbeat cadence (ADR-007: 30s).
const DefaultHeartbeatInterval = 30 * time.Second

// DefaultHeartbeatJitterFraction is applied to the interval as ±jitter so
// independent spokes do not synchronize their beats against one hub. On the
// default 30s cadence this yields a ±5s window, matching ADR-007.
const DefaultHeartbeatJitterFraction = 5.0 / 30.0

// DefaultDeregisterTimeout caps the best-effort deregister request on shutdown.
const DefaultDeregisterTimeout = 2 * time.Second

// spokeStateFileName is the on-disk name for spoke-side state, used to detect
// URL changes across restarts so the spoke can re-register with a new URL.
const spokeStateFileName = "spoke-state.json"

// SpokeState is the per-spoke persistent state. It records the URL last
// advertised to the hub and the stable identity_fingerprint generated on
// first start, both so URL changes can be detected across restarts and so
// re-registration can prove identity to the hub.
type SpokeState struct {
	NodeID              string `json:"node_id"`
	IdentityFingerprint string `json:"identity_fingerprint"`
	LastURL             string `json:"last_url,omitempty"`
}

// DefaultSpokeStatePath returns ~/.local/share/ddx/spoke-state.json (XDG aware).
func DefaultSpokeStatePath() (string, error) {
	if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
		return filepath.Join(xdg, "ddx", spokeStateFileName), nil
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return "", fmt.Errorf("federation: cannot determine home directory: %w", err)
	}
	return filepath.Join(home, ".local", "share", "ddx", spokeStateFileName), nil
}

// LoadSpokeState reads spoke state from path. Missing file → zero value.
func LoadSpokeState(path string) (*SpokeState, error) {
	data, err := os.ReadFile(path)
	if errors.Is(err, os.ErrNotExist) {
		return &SpokeState{}, nil
	}
	if err != nil {
		return nil, fmt.Errorf("federation: read spoke state: %w", err)
	}
	var st SpokeState
	if err := json.Unmarshal(data, &st); err != nil {
		// Corrupt file — start fresh; the caller will overwrite.
		return &SpokeState{}, nil
	}
	return &st, nil
}

// SaveSpokeState writes spoke state to path atomically (tmpfile+rename).
func SaveSpokeState(path string, st *SpokeState) error {
	if st == nil {
		return fmt.Errorf("federation: nil spoke state")
	}
	if err := os.MkdirAll(filepath.Dir(path), dirMode); err != nil {
		return fmt.Errorf("federation: mkdir: %w", err)
	}
	data, err := json.MarshalIndent(st, "", "  ")
	if err != nil {
		return err
	}
	tmp, err := os.CreateTemp(filepath.Dir(path), ".spoke-state-*.json.tmp")
	if err != nil {
		return err
	}
	tmpPath := tmp.Name()
	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		_ = os.Remove(tmpPath)
		return err
	}
	if err := tmp.Close(); err != nil {
		_ = os.Remove(tmpPath)
		return err
	}
	if err := os.Chmod(tmpPath, fileMode); err != nil {
		_ = os.Remove(tmpPath)
		return err
	}
	return os.Rename(tmpPath, path)
}

// generateIdentityFingerprint returns a random 16-byte hex string. The
// fingerprint is generated once per node and persisted in spoke-state so a
// re-registration of the same node_id from the same machine is recognized
// as such (rather than rejected as a duplicate-identity conflict).
func generateIdentityFingerprint() string {
	var buf [16]byte
	if _, err := rand.Read(buf[:]); err != nil {
		// Fall back to a hostname-derived value; collisions here are
		// uninteresting because the hub's duplicate-id rejection only fires
		// on a *different* fingerprint claiming the same node_id.
		host, _ := os.Hostname()
		return "fp-" + host
	}
	return "fp-" + hex.EncodeToString(buf[:])
}

// SpokeConfig configures a Spoke lifecycle agent. URL is the spoke's own
// publicly-reachable URL (advertised to the hub); HubURL is the hub base URL
// (e.g. "https://hub.example:7743").
type SpokeConfig struct {
	NodeID               string
	Name                 string
	URL                  string
	HubURL               string
	DDxVersion           string
	SchemaVersion        string
	GraphQLSchemaVersion string
	Capabilities         []string

	// HeartbeatInterval defaults to DefaultHeartbeatInterval. Pass a small
	// value (e.g. 50ms) in tests.
	HeartbeatInterval time.Duration
	// HeartbeatJitterFraction is the ± jitter as a fraction of the interval
	// (e.g. 0.25 for ±25%). Defaults to DefaultHeartbeatJitterFraction.
	HeartbeatJitterFraction float64
	// DeregisterTimeout caps the best-effort deregister on shutdown.
	DeregisterTimeout time.Duration

	// StatePath is the disk path for spoke-state.json. Empty → DefaultSpokeStatePath.
	StatePath string
	// HTTPClient is used for hub requests. Nil → default client that accepts
	// self-signed certs (matches the server's auto-generated cert).
	HTTPClient *http.Client
	// Logger is used for warn/info; nil → log.Printf.
	Logger func(format string, args ...any)
}

// Spoke is the spoke-side lifecycle agent: register on Start, jittered
// heartbeat in the background, deregister best-effort on Shutdown.
type Spoke struct {
	cfg                 SpokeConfig
	identityFingerprint string

	mu              sync.Mutex
	statePath       string
	registered      bool
	stopped         chan struct{}
	stopOnce        sync.Once
	registeredCount int // test introspection
	heartbeatCount  int // test introspection
	urlChanged      bool
	urlChangedFrom  string
	hbErr           error
	logf            func(format string, args ...any)
}

// NewSpoke constructs a Spoke with defaults filled in. The spoke is not
// started until Start is called.
func NewSpoke(cfg SpokeConfig) (*Spoke, error) {
	if strings.TrimSpace(cfg.NodeID) == "" {
		return nil, fmt.Errorf("federation: spoke NodeID required")
	}
	if strings.TrimSpace(cfg.HubURL) == "" {
		return nil, fmt.Errorf("federation: spoke HubURL required")
	}
	if strings.TrimSpace(cfg.URL) == "" {
		return nil, fmt.Errorf("federation: spoke URL required")
	}
	if cfg.HeartbeatInterval <= 0 {
		cfg.HeartbeatInterval = DefaultHeartbeatInterval
	}
	if cfg.HeartbeatJitterFraction < 0 {
		cfg.HeartbeatJitterFraction = 0
	}
	if cfg.HeartbeatJitterFraction == 0 {
		cfg.HeartbeatJitterFraction = DefaultHeartbeatJitterFraction
	}
	if cfg.DeregisterTimeout <= 0 {
		cfg.DeregisterTimeout = DefaultDeregisterTimeout
	}
	if cfg.HTTPClient == nil {
		// Self-signed certs are the default for ddx-server, so the spoke
		// must skip cert verification by default. Operators wanting stricter
		// validation can pass a custom HTTPClient.
		cfg.HTTPClient = &http.Client{
			Timeout: 10 * time.Second,
			Transport: &http.Transport{
				TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
			},
		}
	}

	statePath := cfg.StatePath
	if statePath == "" {
		p, err := DefaultSpokeStatePath()
		if err != nil {
			return nil, err
		}
		statePath = p
	}

// Package federation defines the hub-side federation registry: state types,
// persistence, and reconciliation helpers. No HTTP layer here — that lands in
// later beads. The on-disk format carries a schema_version field for forward
// compatibility (see ADR-007 and FEAT-026).
package federation

import (
	"fmt"
	"time"
)

// CurrentSchemaVersion is the schema_version this build writes. Reading code
// must accept older versions and migrate; writing code always emits this.
const CurrentSchemaVersion = "1"

// SpokeStatus is the lifecycle/health status of a registered spoke.
//
// The states are:
//   - StatusRegistered: spoke has registered but no heartbeat has been observed yet.
//   - StatusActive:     last heartbeat is recent (the live/healthy state).
//   - StatusStale:      no heartbeat for ≥ 2 minutes.
//   - StatusOffline:    fan-out to the spoke failed (connection refused, unreachable).
//   - StatusDegraded:   version handshake accepted with minor/schema drift.
//
// The bead-level enum collapses ADR-007's split between compat_status and
// liveness into a single field for v1 persistence; richer surface fields can
// be added in later schema versions without breaking older readers.
type SpokeStatus string

const (
	StatusRegistered SpokeStatus = "registered"
	StatusActive     SpokeStatus = "active"
	StatusStale      SpokeStatus = "stale"
	StatusOffline    SpokeStatus = "offline"
	StatusDegraded   SpokeStatus = "degraded"
)

// Valid reports whether s is one of the known status values.
func (s SpokeStatus) Valid() bool {
	switch s {
	case StatusRegistered, StatusActive, StatusStale, StatusOffline, StatusDegraded:
		return true
	}
	return false
}

// SpokeRecord is one entry in the federation registry.
type SpokeRecord struct {
	NodeID        string      `json:"node_id"`
	Name          string      `json:"name"`
	URL           string      `json:"url"`
	DDxVersion    string      `json:"ddx_version,omitempty"`
	SchemaVersion string      `json:"schema_version,omitempty"`
	Capabilities  []string    `json:"capabilities,omitempty"`
	RegisteredAt  time.Time   `json:"registered_at"`
	LastHeartbeat time.Time   `json:"last_heartbeat"`
	Status        SpokeStatus `json:"status"`
}

// FederationRegistry is the persisted hub state.
type FederationRegistry struct {
	SchemaVersion string        `json:"schema_version"`
	Spokes        []SpokeRecord `json:"spokes"`
}

// NewRegistry returns an empty registry stamped with the current schema version.
func NewRegistry() *FederationRegistry {
	return &FederationRegistry{
		SchemaVersion: CurrentSchemaVersion,
		Spokes:        []SpokeRecord{},
	}
}

// FindSpoke returns the record for nodeID, or nil if absent.
func (r *FederationRegistry) FindSpoke(nodeID string) *SpokeRecord {
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == nodeID {
			return &r.Spokes[i]
		}
	}
	return nil
}

// UpsertSpoke inserts or replaces a spoke by NodeID. NodeID must be non-empty.
func (r *FederationRegistry) UpsertSpoke(rec SpokeRecord) error {
	if rec.NodeID == "" {
		return fmt.Errorf("federation: spoke node_id is required")
	}
	if rec.Status == "" {
		rec.Status = StatusRegistered
	}
	if !rec.Status.Valid() {
		return fmt.Errorf("federation: invalid spoke status %q", rec.Status)
	}
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == rec.NodeID {
			r.Spokes[i] = rec
			return nil
		}
	}
	r.Spokes = append(r.Spokes, rec)
	return nil
}

// RemoveSpoke removes a spoke by NodeID; reports whether it was present.
func (r *FederationRegistry) RemoveSpoke(nodeID string) bool {
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == nodeID {
			r.Spokes = append(r.Spokes[:i], r.Spokes[i+1:]...)
			return true
		}
	}
	return false
}

// SetStatus updates the status of a spoke and returns true on success. Refuses
// unknown status values so callers cannot silently corrupt persisted state.
func (r *FederationRegistry) SetStatus(nodeID string, status SpokeStatus) error {
	if !status.Valid() {
		return fmt.Errorf("federation: invalid status %q", status)
	}
	rec := r.FindSpoke(nodeID)
	if rec == nil {
		return fmt.Errorf("federation: spoke %q not found", nodeID)
	}
	rec.Status = status
	return nil
}

// ReconcileLiveness derives status purely from elapsed time since the last
// heartbeat for spokes whose status is currently in {registered, active,
// stale}. Statuses set externally (offline from fan-out failure, degraded from
// version handshake) are left alone — those are not time-driven.
//
//   - now - last_heartbeat <  staleAfter            → active
//   - now - last_heartbeat >= staleAfter            → stale
//
// A zero LastHeartbeat keeps a freshly-registered spoke in StatusRegistered
// until the first heartbeat is observed.
func (r *FederationRegistry) ReconcileLiveness(now time.Time, staleAfter time.Duration) {
	for i := range r.Spokes {
		s := &r.Spokes[i]
		switch s.Status {
		case StatusOffline, StatusDegraded:
			continue
		}
		if s.LastHeartbeat.IsZero() {
			s.Status = StatusRegistered
			continue
		}
		if now.Sub(s.LastHeartbeat) >= staleAfter {
			s.Status = StatusStale
		} else {
			s.Status = StatusActive
		}
	}
}

package server

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/federation"
)

// HubDefaultDDxVersion is the ddx_version the hub advertises when validating
// spoke handshakes. It is exposed as a field so tests and operators can pin
// the hub's view of "current ddx version" without rebuilding the binary.
const HubDefaultDDxVersion = "0.1.0"

// federationHub holds the per-server state for hub-mode federation: the
// in-memory registry, the disk path used to persist it, the warning logger
// (for plain-HTTP accepted registrations), and configuration knobs.
type federationHub struct {
	mu             sync.Mutex
	registry       *federation.FederationRegistry
	statePath      string // empty disables disk persistence
	allowPlainHTTP bool
	hubDDxVersion  string
	hubSchemaVer   string
	warnLog        func(format string, args ...any)
	warnings       []string // captured plain-HTTP warnings (test introspection)
	conflictsLog   []string // captured 409 conflict log lines (test introspection)
	now            func() time.Time
}

// EnableHubMode mounts the /api/federation/* routes on this server, switches
// the hub-mode flag on, and (best effort) loads the registry from disk so a
// hub restart can rebuild state from a prior session.
//
// Must be called before ListenAndServe / ListenAndServeTLS. Calling it more
// than once is a no-op after the first call.
//
// allowPlainHTTP relaxes the default ts-net/loopback peer policy on the
// federation routes — non-trusted peers are accepted, but each accepted
// registration emits a WARN log entry. This is the operator opt-out for
// federations spanning networks where ts-net is not viable.
func (s *Server) EnableHubMode(allowPlainHTTP bool) {
	if s.hub != nil {
		return
	}
	statePath, err := federation.DefaultStatePath()
	if err != nil {
		statePath = ""
	}
	var reg *federation.FederationRegistry
	if statePath != "" {
		if loaded, lerr := federation.LoadStateFrom(statePath); lerr == nil {
			reg = loaded
		}
	}
	if reg == nil {
		reg = federation.NewRegistry()
	}
	s.hub = &federationHub{
		registry:       reg,
		statePath:      statePath,
		allowPlainHTTP: allowPlainHTTP,
		hubDDxVersion:  HubDefaultDDxVersion,
		hubSchemaVer:   federation.CurrentSchemaVersion,
		warnLog:        func(format string, args ...any) { log.Printf("WARN: "+format, args...) },
		now:            time.Now,
	}
	s.HubMode = true

	gate := func(h http.HandlerFunc) http.HandlerFunc { return s.requireFederationTrusted(h) }
	s.route("POST /api/federation/register", gate(s.handleFederationRegister))
	s.route("POST /api/federation/heartbeat", gate(s.handleFederationHeartbeat))
	s.route("GET /api/federation/spokes", gate(s.handleFederationListSpokes))
	s.route("DELETE /api/federation/spokes/{id}", gate(s.handleFederationDeregister))
}

// HubFederationRegistrySnapshot returns a copy of the current registry, for
// tests and operator introspection.
func (s *Server) HubFederationRegistrySnapshot() *federation.FederationRegistry {
	if s.hub == nil {
		return nil
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	out := federation.NewRegistry()
	out.SchemaVersion = s.hub.registry.SchemaVersion
	out.Spokes = append(out.Spokes, s.hub.registry.Spokes...)
	return out
}

// HubFederationWarnings returns plain-HTTP-accepted-registration WARN messages
// captured since the server started. Test-only helper.
func (s *Server) HubFederationWarnings() []string {
	if s.hub == nil {
		return nil
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	return append([]string(nil), s.hub.warnings...)
}

// HubFederationConflicts returns 409 conflict log messages captured since the
// server started. Test-only helper.
func (s *Server) HubFederationConflicts() []string {
	if s.hub == nil {
		return nil
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	return append([]string(nil), s.hub.conflictsLog...)
}

// requireFederationTrusted enforces the federation-specific peer policy:
// loopback / ts-net peers are always accepted; non-trusted peers are accepted
// only when --federation-allow-plain-http is set. Distinct from
// requireTrusted so the AC-strict default doesn't depend on a global flag.
func (s *Server) requireFederationTrusted(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if isTrusted(r) {
			next(w, r)
			return
		}
		if s.hub != nil && s.hub.allowPlainHTTP {
			next(w, r)
			return
		}
		writeJSON(w, http.StatusForbidden, map[string]string{"error": "forbidden: ts-net or loopback peer required for /api/federation/* (use --federation-allow-plain-http to opt out)"})
	}
}

// federationRegisterRequest is the spoke→hub registration / re-registration
// payload. Identity = (NodeID, IdentityFingerprint). NodeID is the stable
// federation key; IdentityFingerprint distinguishes a re-registration of the
// same node from a duplicate-name conflict (different machine claiming an
// already-registered node_id).
type federationRegisterRequest struct {
	NodeID               string   `json:"node_id"`
	IdentityFingerprint  string   `json:"identity_fingerprint,omitempty"`
	Name                 string   `json:"name"`
	URL                  string   `json:"url"`
	DDxVersion           string   `json:"ddx_version"`
	SchemaVersion        string   `json:"schema_version"`
	GraphQLSchemaVersion string   `json:"graphql_schema_version,omitempty"`
	Capabilities         []string `json:"capabilities,omitempty"`
}

// federationRegisterResponse is sent on a successful (200/201) registration.
type federationRegisterResponse struct {
	NodeID string                 `json:"node_id"`
	Status federation.SpokeStatus `json:"status"`
	Reason string                 `json:"reason"`
	Spoke  federation.SpokeRecord `json:"spoke"`
}

// identityFingerprintKey is the SpokeRecord.Capabilities-adjacent slot we
// stash the fingerprint in. To keep the on-disk schema stable (B14.2 froze
// SpokeRecord shape), we encode it as a synthetic capability prefixed with
// "@identity:". Future schema versions can hoist it to a first-class field.
const identityFingerprintPrefix = "@identity:"

func setIdentityFingerprint(rec *federation.SpokeRecord, fp string) {
	cleaned := rec.Capabilities[:0]
	for _, c := range rec.Capabilities {
		if !strings.HasPrefix(c, identityFingerprintPrefix) {
			cleaned = append(cleaned, c)
		}
	}
	rec.Capabilities = cleaned
	if fp != "" {
		rec.Capabilities = append(rec.Capabilities, identityFingerprintPrefix+fp)
	}
}

func getIdentityFingerprint(rec federation.SpokeRecord) string {
	for _, c := range rec.Capabilities {
		if strings.HasPrefix(c, identityFingerprintPrefix) {
			return strings.TrimPrefix(c, identityFingerprintPrefix)
		}
	}
	return ""
}

func (s *Server) handleFederationRegister(w http.ResponseWriter, r *http.Request) {
	var req federationRegisterRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid json: " + err.Error()})
		return
	}
	req.NodeID = strings.TrimSpace(req.NodeID)
	if req.NodeID == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "node_id required"})
		return
	}
	if strings.TrimSpace(req.URL) == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "url required"})
		return
	}

	hs := federation.Handshake(s.hub.hubDDxVersion, s.hub.hubSchemaVer, req.DDxVersion, req.SchemaVersion)
	if !hs.Accept {
		writeJSON(w, http.StatusBadRequest, map[string]string{
			"error":  "version handshake failed",
			"reason": hs.Reason,
		})
		return
	}

	now := s.hub.now().UTC()

	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()

	if existing := s.hub.registry.FindSpoke(req.NodeID); existing != nil {
		existingFP := getIdentityFingerprint(*existing)
		// Identity conflict: a different machine claims an already-registered
		// node_id. Reject with 409 and log.
		if existingFP != "" && req.IdentityFingerprint != "" && existingFP != req.IdentityFingerprint {
			msg := fmt.Sprintf("federation: duplicate node_id %q from different identity (existing=%s, attempted=%s)",
				req.NodeID, existingFP, req.IdentityFingerprint)
			s.hub.conflictsLog = append(s.hub.conflictsLog, msg)
			s.hub.warnLog("%s", msg)
			writeJSON(w, http.StatusConflict, map[string]string{
				"error":  "node_id already registered to a different identity",
				"reason": "duplicate_node_id",
			})
			return
		}
	}

	rec := federation.SpokeRecord{
		NodeID:        req.NodeID,
		Name:          req.Name,
		URL:           req.URL,
		DDxVersion:    req.DDxVersion,
		SchemaVersion: req.SchemaVersion,
		Capabilities:  append([]string(nil), req.Capabilities...),
		RegisteredAt:  now,
		LastHeartbeat: time.Time{},
		Status:        hs.Status,
	}
	setIdentityFingerprint(&rec, req.IdentityFingerprint)
	if err := s.hub.registry.UpsertSpoke(rec); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": err.Error()})
		return
	}
	s.persistFederationLocked()

	// Emit WARN if this registration was accepted via the plain-HTTP opt-out.
	if s.hub.allowPlainHTTP && !isTrusted(r) {
		msg := fmt.Sprintf("federation: accepted plain-HTTP registration node_id=%q url=%q from remote=%s",
			req.NodeID, req.URL, r.RemoteAddr)
		s.hub.warnings = append(s.hub.warnings, msg)
		s.hub.warnLog("%s", msg)
	}

package server

import (
	"context"
	"sync"

	"github.com/DocumentDrivenDX/ddx/internal/federation"
	ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
)

// hubFederationProvider adapts a *federationHub to the
// ddxgraphql.FederationProvider interface so federationNodes /
// federated{Beads,Runs,Projects} resolvers can read live registry state and
// drive fan-out against registered spokes.
//
// The provider applies StatusUpdates from each fan-out result back to the
// registry on the same lock the hub uses, so subsequent /federation page
// loads (or fan-out queries) observe the propagated transport-level
// status (offline) without an out-of-band reconcile loop.
type hubFederationProvider struct {
	server *Server
	once   sync.Once
	client *federation.FanOutClient
}

func newHubFederationProvider(s *Server) *hubFederationProvider {
	return &hubFederationProvider{server: s}
}

// fanOutClient is lazy-built so tests that swap s.hub mid-run see a fresh
// client wired to the latest hub config.
func (p *hubFederationProvider) fanOutClient() *federation.FanOutClient {
	p.once.Do(func() {
		c := federation.NewFanOutClient()
		c.HubDDxVersion = p.server.hub.hubDDxVersion
		c.HubSchemaVersion = p.server.hub.hubSchemaVer
		p.client = c
	})
	return p.client
}

// Spokes returns a copy of the current registry's spokes.
func (p *hubFederationProvider) Spokes() []federation.SpokeRecord {
	if p.server.hub == nil {
		return nil
	}
	p.server.hub.mu.Lock()
	defer p.server.hub.mu.Unlock()
	out := make([]federation.SpokeRecord, len(p.server.hub.registry.Spokes))
	copy(out, p.server.hub.registry.Spokes)
	return out
}

// FanOut runs req against every registered spoke and applies any returned
// StatusUpdates back to the registry (so transport-level offline transitions
// surface on the next /federation load).
func (p *hubFederationProvider) FanOut(ctx context.Context, req *federation.FanOutRequest) (*federation.FanOutResult, error) {
	if p.server.hub == nil {
		return &federation.FanOutResult{}, nil
	}
	spokes := p.Spokes()
	res, err := p.fanOutClient().Execute(ctx, spokes, req)
	if err != nil || res == nil {
		return res, err
	}
	if len(res.StatusUpdates) > 0 {
		p.server.hub.mu.Lock()
		for nodeID, st := range res.StatusUpdates {
			_ = p.server.hub.registry.SetStatus(nodeID, st)
		}
		p.server.persistFederationLocked()
		p.server.hub.mu.Unlock()
	}
	return res, nil
}

// Compile-time assertion that hubFederationProvider satisfies the resolver
// contract.
var _ ddxgraphql.FederationProvider = (*hubFederationProvider)(nil)

package federation

import (
	"bytes"
	"context"
	"crypto/tls"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"net/http"
	"net/url"
	"strings"
	"sync"
	"time"
)

// DefaultFanOutMaxConcurrency caps the number of in-flight per-spoke requests.
const DefaultFanOutMaxConcurrency = 8

// DefaultFanOutPerNodeTimeout is the default per-node deadline for one fan-out call.
const DefaultFanOutPerNodeTimeout = 5 * time.Second

// SkipReason is a short, machine-readable code describing why a spoke was
// skipped before any HTTP call was issued.
type SkipReason string

const (
	// SkipReasonIncompatibleVersion indicates the version handshake against the
	// hub's own version+schema rejected this spoke (e.g. major mismatch,
	// schema mismatch, unparseable ddx_version, …). The Handshake reason is
	// included in the logged message.
	SkipReasonIncompatibleVersion SkipReason = "incompatible_version"
	// SkipReasonMissingCapability indicates the spoke does not advertise one of
	// the capabilities required for this query.
	SkipReasonMissingCapability SkipReason = "missing_capability"
	// SkipReasonInvalidURL indicates the spoke's persisted URL did not parse.
	SkipReasonInvalidURL SkipReason = "invalid_url"
)

// NodeOutcomeKind describes how a single spoke contributed (or did not
// contribute) to a fan-out call. The hub uses this to update per-spoke status
// distinctly: offline (immediate transport failure on this fan-out) vs stale
// (heartbeat-overdue badge from the registry) vs ok.
type NodeOutcomeKind string

const (
	// OutcomeOK means the spoke returned a response (any HTTP 2xx).
	OutcomeOK NodeOutcomeKind = "ok"
	// OutcomeOffline means the transport itself failed: connection refused,
	// DNS error, TLS handshake failed, mid-response disconnect, etc. The hub
	// flips the spoke's registry status to StatusOffline on this outcome.
	OutcomeOffline NodeOutcomeKind = "offline"
	// OutcomeTimeout means the per-node timeout fired before a response was
	// fully received. Distinct from offline so callers can keep the spoke's
	// last-known status (likely stale) rather than promote it to offline.
	OutcomeTimeout NodeOutcomeKind = "timeout"
	// OutcomeHTTPError means the spoke responded with a non-2xx status. The
	// transport worked, so we do not flip to offline; the body is captured.
	OutcomeHTTPError NodeOutcomeKind = "http_error"
	// OutcomeSkipped means the spoke was filtered out before fan-out; see
	// NodeResult.SkipReason.
	OutcomeSkipped NodeOutcomeKind = "skipped"
)

// FanOutRequest is the GraphQL payload to send to every active spoke.
type FanOutRequest struct {
	Query         string         `json:"query"`
	OperationName string         `json:"operationName,omitempty"`
	Variables     map[string]any `json:"variables,omitempty"`
	// RequiredCapabilities, if non-empty, filters out spokes that do not
	// advertise every named capability in their SpokeRecord.Capabilities.
	RequiredCapabilities []string `json:"-"`
}

// NodeResult is a single spoke's contribution to a fan-out call.
type NodeResult struct {
	NodeID string
	URL    string
	// Status, when non-empty, is the registry status the hub should record for
	// this spoke as a result of this fan-out (StatusOffline on transport
	// failure). Empty means "do not change registry status".
	Status SpokeStatus
	// Outcome classifies how this spoke contributed.
	Outcome NodeOutcomeKind
	// Response is the raw GraphQL response body for OutcomeOK. The hub merges
	// it into the federated response shape. Empty otherwise.
	Response json.RawMessage
	// HTTPStatus is the HTTP status code seen, or 0 on transport failure.
	HTTPStatus int
	// Err is the underlying error for non-OK outcomes.
	Err error
	// SkipReason is set when Outcome == OutcomeSkipped.
	SkipReason SkipReason
	// SkipDetail is a free-form human message accompanying SkipReason.
	SkipDetail string
	// Duration is the wall time spent on this spoke's call.
	Duration time.Duration
}

// FanOutResult is the merged outcome of a fan-out call.
type FanOutResult struct {
	// Responses holds one entry per spoke that returned 2xx, keyed by node_id.
	// The value is the raw GraphQL response body.
	Responses map[string]json.RawMessage
	// Errors holds one entry per spoke that produced any non-OK outcome
	// (offline, timeout, http_error). Skipped spokes are NOT in this map —
	// they appear in Skipped instead. Keyed by node_id.
	Errors map[string]error
	// Skipped holds one entry per spoke filtered out before fan-out, keyed by
	// node_id, with the SkipReason as the value.
	Skipped map[string]SkipReason
	// StatusUpdates lists the (node_id → new status) changes the hub should
	// apply to its registry as a side effect of this fan-out. Currently only
	// transport-level failures (StatusOffline) are emitted here; heartbeat-
	// driven status (stale) is left to the registry's own time-based reconcile.
	StatusUpdates map[string]SpokeStatus
	// Nodes is the per-node detail (every spoke considered, including skipped).
	// Order matches the input registry order for deterministic test output.
	Nodes []NodeResult
}

// FanOutClient executes fan-out GraphQL queries across a federation registry.
type FanOutClient struct {
	// HTTPClient is used for spoke /graphql calls. Nil → a default client that
	// accepts self-signed TLS certs (matches the spoke server's auto-cert).
	HTTPClient *http.Client
	// MaxConcurrency caps concurrent in-flight requests. ≤0 → default.
	MaxConcurrency int
	// PerNodeTimeout is the per-spoke deadline. ≤0 → default.
	PerNodeTimeout time.Duration
	// HubDDxVersion / HubSchemaVersion drive the version handshake gate.
	// Empty → version filter is skipped (test convenience).
	HubDDxVersion    string
	HubSchemaVersion string
	// Logger receives info/warn lines; nil → log.Printf.
	Logger func(format string, args ...any)
	// Now is the time source used for Duration measurement. Nil → time.Now.
	Now func() time.Time
}

// NewFanOutClient builds a FanOutClient with defaults filled in.
func NewFanOutClient() *FanOutClient {
	return &FanOutClient{
		HTTPClient: &http.Client{
			// Per-request deadlines drive cancellation; this is just a safety
			// net for misbehaving servers that never close the connection.
			Timeout: 30 * time.Second,
			Transport: &http.Transport{
				TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
			},
		},
		MaxConcurrency: DefaultFanOutMaxConcurrency,
		PerNodeTimeout: DefaultFanOutPerNodeTimeout,
	}
}

func (c *FanOutClient) logf(format string, args ...any) {
	if c.Logger != nil {
		c.Logger(format, args...)
		return
	}
	log.Printf(format, args...)
}

func (c *FanOutClient) now() time.Time {
	if c.Now != nil {
		return c.Now()
	}
	return time.Now()
}

func (c *FanOutClient) maxConcurrency() int {
	if c.MaxConcurrency <= 0 {
		return DefaultFanOutMaxConcurrency
	}
	return c.MaxConcurrency
}

func (c *FanOutClient) perNodeTimeout() time.Duration {
	if c.PerNodeTimeout <= 0 {
		return DefaultFanOutPerNodeTimeout
	}
	return c.PerNodeTimeout
}

func (c *FanOutClient) httpClient() *http.Client {
	if c.HTTPClient != nil {
		return c.HTTPClient
	}
	return http.DefaultClient
}

// Execute fans out req across spokes. Returns a merged FanOutResult; never
// returns a non-nil error for per-spoke failures — those are surfaced through
// FanOutResult.Errors. A non-nil error is reserved for misuse (e.g. nil req).
//
// The set of spokes considered is the input slice. Callers typically pass the
// hub registry's spokes filtered by Status == active|stale (offline/degraded
// handling depends on policy and is left to the caller). Skipped spokes still
// appear in the per-node Nodes detail with OutcomeSkipped + SkipReason.
//
// Cancellation: if ctx is canceled, in-flight goroutines abort their HTTP
// calls and return OutcomeOffline (with ctx.Err() as cause); callers that want
// to distinguish caller-cancellation from spoke failure should check ctx.Err()
// after Execute returns.
func (c *FanOutClient) Execute(ctx context.Context, spokes []SpokeRecord, req *FanOutRequest) (*FanOutResult, error) {
	if req == nil {
		return nil, errors.New("federation: fanout request is nil")
	}
	if strings.TrimSpace(req.Query) == "" {
		return nil, errors.New("federation: fanout request query is empty")
	}

	body, err := json.Marshal(struct {
		Query         string         `json:"query"`
		OperationName string         `json:"operationName,omitempty"`
		Variables     map[string]any `json:"variables,omitempty"`
	}{req.Query, req.OperationName, req.Variables})
	if err != nil {
		return nil, fmt.Errorf("federation: marshal fanout query: %w", err)
	}

	results := make([]NodeResult, len(spokes))
	sem := make(chan struct{}, c.maxConcurrency())
	var wg sync.WaitGroup

	for i := range spokes {
		i := i
		s := spokes[i]
		// Pre-flight filters: version, capability, URL.
		if skip, reason, detail := c.preflightSkip(s, req.RequiredCapabilities); skip {
			c.logf("federation fanout: skip node_id=%q reason=%s detail=%q", s.NodeID, reason, detail)
			results[i] = NodeResult{
				NodeID:     s.NodeID,
				URL:        s.URL,
				Outcome:    OutcomeSkipped,
				SkipReason: reason,
				SkipDetail: detail,
			}
			continue
		}

		wg.Add(1)
		go func() {
			defer wg.Done()
			select {
			case sem <- struct{}{}:
			case <-ctx.Done():
				results[i] = NodeResult{
					NodeID:  s.NodeID,
					URL:     s.URL,
					Outcome: OutcomeOffline,
					Status:  StatusOffline,
					Err:     ctx.Err(),
				}
				return
			}
			defer func() { <-sem }()

			defer func() { <-sem }()
			results[i] = c.callOne(ctx, s, body)
		}()
	}
	wg.Wait()

	out := &FanOutResult{
		Responses:     map[string]json.RawMessage{},
		Errors:        map[string]error{},
		Skipped:       map[string]SkipReason{},
		StatusUpdates: map[string]SpokeStatus{},
		Nodes:         results,
	}
	for _, r := range results {
		switch r.Outcome {
		case OutcomeOK:
			out.Responses[r.NodeID] = r.Response
		case OutcomeSkipped:
			out.Skipped[r.NodeID] = r.SkipReason
		default:
			if r.Err != nil {
				out.Errors[r.NodeID] = r.Err
			} else {
				out.Errors[r.NodeID] = fmt.Errorf("fanout: %s", r.Outcome)
			}
		}
		if r.Status != "" {
			out.StatusUpdates[r.NodeID] = r.Status
		}
	}
	return out, nil
}

// preflightSkip returns (true, reason, detail) when the spoke must be skipped
// before any HTTP call is issued.
func (c *FanOutClient) preflightSkip(s SpokeRecord, requiredCaps []string) (bool, SkipReason, string) {
	if c.HubDDxVersion != "" && c.HubSchemaVersion != "" {
		hs := Handshake(c.HubDDxVersion, c.HubSchemaVersion, s.DDxVersion, s.SchemaVersion)
		if !hs.Accept {
			return true, SkipReasonIncompatibleVersion, hs.Reason
		}
	}
	if len(requiredCaps) > 0 {
		have := map[string]struct{}{}
		for _, c := range s.Capabilities {
			// Skip the synthetic identity-fingerprint capability.
			if strings.HasPrefix(c, "@identity:") {
				continue
			}
			have[c] = struct{}{}
		}
		for _, want := range requiredCaps {
			if _, ok := have[want]; !ok {
				return true, SkipReasonMissingCapability, want
			}
		}
	}
	if strings.TrimSpace(s.URL) == "" {
		return true, SkipReasonInvalidURL, "empty url"
	}
	if _, err := url.Parse(s.URL); err != nil {
		return true, SkipReasonInvalidURL, err.Error()
	}
	return false, "", ""
}

// callOne issues the GraphQL POST against one spoke under per-node timeout.
func (c *FanOutClient) callOne(ctx context.Context, s SpokeRecord, body []byte) NodeResult {
	start := c.now()
	cctx, cancel := context.WithTimeout(ctx, c.perNodeTimeout())
	defer cancel()

	endpoint := strings.TrimRight(s.URL, "/") + "/graphql"
	req, err := http.NewRequestWithContext(cctx, http.MethodPost, endpoint, bytes.NewReader(body))
	if err != nil {
		return NodeResult{
			NodeID:   s.NodeID,
			URL:      s.URL,
			Outcome:  OutcomeOffline,
			Status:   StatusOffline,
			Err:      err,
			Duration: c.now().Sub(start),
		}
	}
	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Accept", "application/json")

	resp, err := c.httpClient().Do(req)
	if err != nil {
		// Distinguish per-node timeout (deadline exceeded on cctx but parent
		// ctx still live) from caller cancellation and from generic transport
		// failure. Per-node timeout → keep last-known status; transport
		// failure → flip to offline.
		if cctx.Err() == context.DeadlineExceeded && ctx.Err() == nil {
			return NodeResult{
				NodeID:   s.NodeID,
				URL:      s.URL,
				Outcome:  OutcomeTimeout,
				Err:      fmt.Errorf("per-node timeout after %s: %w", c.perNodeTimeout(), err),
				Duration: c.now().Sub(start),
			}
		}
		return NodeResult{
			NodeID:   s.NodeID,
			URL:      s.URL,
			Outcome:  OutcomeOffline,
			Status:   StatusOffline,
			Err:      err,
			Duration: c.now().Sub(start),
		}
	}
	defer func() { _ = resp.Body.Close() }()

	buf, readErr := io.ReadAll(resp.Body)
	if readErr != nil {
		// Mid-response disconnect — transport-level failure → offline.
		return NodeResult{
			NodeID:     s.NodeID,
			URL:        s.URL,
			Outcome:    OutcomeOffline,
			Status:     StatusOffline,
			HTTPStatus: resp.StatusCode,
			Err:        fmt.Errorf("read body: %w", readErr),
			Duration:   c.now().Sub(start),
		}
	}

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		snippet := string(buf)
		if len(snippet) > 256 {
			snippet = snippet[:256] + "…"
		}
		return NodeResult{
			NodeID:     s.NodeID,
			URL:        s.URL,
			Outcome:    OutcomeHTTPError,
			HTTPStatus: resp.StatusCode,
			Err:        fmt.Errorf("spoke returned HTTP %d: %s", resp.StatusCode, snippet),
			Duration:   c.now().Sub(start),
		}
	}

	return NodeResult{
		NodeID:     s.NodeID,
		URL:        s.URL,
		Outcome:    OutcomeOK,
		HTTPStatus: resp.StatusCode,
		Response:   json.RawMessage(buf),
		Duration:   c.now().Sub(start),
	}
}

	writeJSON(w, http.StatusOK, federationRegisterResponse{
		NodeID: rec.NodeID,
		Status: rec.Status,
		Reason: hs.Reason,
		Spoke:  rec,
	})
}

type federationHeartbeatRequest struct {
	NodeID string `json:"node_id"`
}

func (s *Server) handleFederationHeartbeat(w http.ResponseWriter, r *http.Request) {
	var req federationHeartbeatRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid json: " + err.Error()})
		return
	}
	req.NodeID = strings.TrimSpace(req.NodeID)
	if req.NodeID == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "node_id required"})
		return
	}

	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()

	rec := s.hub.registry.FindSpoke(req.NodeID)
	if rec == nil {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": "spoke not registered"})
		return
	}
	now := s.hub.now().UTC()
	rec.LastHeartbeat = now
	// Heartbeat clears registered-on-first-seen and offline; preserves
	// degraded (set by the version handshake at registration time).
	if rec.Status == federation.StatusRegistered || rec.Status == federation.StatusOffline || rec.Status == federation.StatusStale {
		rec.Status = federation.StatusActive
	}
	s.persistFederationLocked()

	writeJSON(w, http.StatusOK, map[string]any{
		"node_id":        rec.NodeID,
		"status":         rec.Status,
		"last_heartbeat": rec.LastHeartbeat,
	})
}

func (s *Server) handleFederationListSpokes(w http.ResponseWriter, _ *http.Request) {
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	out := make([]federation.SpokeRecord, 0, len(s.hub.registry.Spokes))
	out = append(out, s.hub.registry.Spokes...)
	writeJSON(w, http.StatusOK, map[string]any{
		"schema_version": s.hub.registry.SchemaVersion,
		"spokes":         out,
	})
}

func (s *Server) handleFederationDeregister(w http.ResponseWriter, r *http.Request) {
	id := strings.TrimSpace(r.PathValue("id"))
	if id == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "id required"})
		return
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	if !s.hub.registry.RemoveSpoke(id) {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": "spoke not found"})
		return
	}
	s.persistFederationLocked()
	writeJSON(w, http.StatusOK, map[string]string{"node_id": id, "status": "deregistered"})
}

// persistFederationLocked saves the registry to disk if a state path is set.
// Caller must hold s.hub.mu.
func (s *Server) persistFederationLocked() {
	if s.hub.statePath == "" {
		return
	}
	if err := federation.SaveStateTo(s.hub.statePath, s.hub.registry); err != nil {
		s.hub.warnLog("federation: persist state: %v", err)
	}
}

package server

import (
	"bytes"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/federation"
)

// federationDoRequest is a small helper that runs a request against an
// httptest.NewServer wrapping s.Handler() so we exercise the real net/http
// stack (RemoteAddr is populated by the test server, matching production
// trust-gating behavior). Pass remote="loopback" for trusted, "external"
// for an explicitly non-loopback request.
func federationDoRequest(t *testing.T, s *Server, method, path string, body any, remote string) *http.Response {
	t.Helper()
	var buf bytes.Buffer
	if body != nil {
		if err := json.NewEncoder(&buf).Encode(body); err != nil {
			t.Fatalf("encode: %v", err)
		}
	}
	req := httptest.NewRequest(method, path, &buf)
	req.Header.Set("Content-Type", "application/json")
	switch remote {
	case "external":
		req.RemoteAddr = "203.0.113.1:54321"
	default:
		req.RemoteAddr = "127.0.0.1:54321"
	}
	rec := httptest.NewRecorder()
	s.Handler().ServeHTTP(rec, req)
	return rec.Result()
}

func newHubServer(t *testing.T, allowPlainHTTP bool) *Server {
	t.Helper()
	dir := setupTestDir(t)
	s := New(":0", dir)
	s.EnableHubMode(allowPlainHTTP)
	// Pin hub version for handshake tests.
	s.hub.hubDDxVersion = "0.10.5"
	s.hub.hubSchemaVer = "1"
	return s
}

func decodeBody(t *testing.T, resp *http.Response, dst any) {
	t.Helper()
	if err := json.NewDecoder(resp.Body).Decode(dst); err != nil {
		t.Fatalf("decode: %v", err)
	}
}

// AC: Routes mounted only when --hub-mode.
func TestFederationRoutesNotMountedWithoutHubMode(t *testing.T) {
	dir := setupTestDir(t)
	s := New(":0", dir)
	// Hub mode NOT enabled — federation routes must not be on the mux at all.
	for _, p := range s.routePatterns {
		if strings.Contains(p, "/api/federation/") {
			t.Fatalf("federation route registered without EnableHubMode: %s", p)
		}
	}
	// And a register request must not produce a federation register response
	// (no node_id-bearing JSON body); the request falls through to the SPA
	// fallback or a non-2xx error, but never the federation handler.
	resp := federationDoRequest(t, s, "POST", "/api/federation/register",
		map[string]string{"node_id": "n1"}, "loopback")
	var maybe federationRegisterResponse
	_ = json.NewDecoder(resp.Body).Decode(&maybe)
	if maybe.NodeID == "n1" {
		t.Fatalf("federation register handler ran with hub-mode off")
	}
}

// AC: routes mounted when hub-mode enabled.
func TestFederationRoutesMountedInHubMode(t *testing.T) {
	s := newHubServer(t, false)
	want := []string{
		"POST /api/federation/register",
		"POST /api/federation/heartbeat",
		"GET /api/federation/spokes",
		"DELETE /api/federation/spokes/{id}",
	}
	have := map[string]bool{}
	for _, p := range s.routePatterns {
		have[p] = true
	}
	for _, p := range want {
		if !have[p] {
			t.Errorf("expected route %q not mounted", p)
		}
	}
}

func goodRegisterPayload(node string) map[string]any {
	return map[string]any{
		"node_id":              node,
		"identity_fingerprint": "fp-" + node,
		"name":                 "spoke-" + node,
		"url":                  "https://" + node + ":7743",
		"ddx_version":          "0.10.5",
		"schema_version":       "1",
		"capabilities":         []string{"beads", "runs"},
	}
}

// AC: Re-register same node_id replaces by id. URL change updates registry.
func TestFederationRegisterIdempotentByNodeID(t *testing.T) {
	s := newHubServer(t, false)

	resp := federationDoRequest(t, s, "POST", "/api/federation/register", goodRegisterPayload("n1"), "loopback")
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("first register: %d", resp.StatusCode)
	}

	// Re-register: same node_id, same identity, NEW url.
	body := goodRegisterPayload("n1")
	body["url"] = "https://updated:7743"
	resp = federationDoRequest(t, s, "POST", "/api/federation/register", body, "loopback")
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("re-register: %d", resp.StatusCode)
	}

	snap := s.HubFederationRegistrySnapshot()
	if got := len(snap.Spokes); got != 1 {
		t.Fatalf("want 1 spoke after re-register, got %d", got)
	}
	if snap.Spokes[0].URL != "https://updated:7743" {
		t.Errorf("URL change did not update registry: got %q", snap.Spokes[0].URL)
	}
}

// AC: Duplicate node_id from different identity returns 409 + log.
func TestSpokeLifecycle_DuplicateNodeID_Rejected(t *testing.T) {
	s := newHubServer(t, false)

	resp := federationDoRequest(t, s, "POST", "/api/federation/register", goodRegisterPayload("n1"), "loopback")
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("first register: %d", resp.StatusCode)
	}

	// Same node_id, DIFFERENT identity_fingerprint.
	body := goodRegisterPayload("n1")
	body["identity_fingerprint"] = "fp-other-machine"
	resp = federationDoRequest(t, s, "POST", "/api/federation/register", body, "loopback")
	if resp.StatusCode != http.StatusConflict {
		t.Fatalf("want 409 on identity conflict, got %d", resp.StatusCode)
	}

	conflicts := s.HubFederationConflicts()
	if len(conflicts) == 0 {
		t.Errorf("expected a conflict log entry; got none")
	}
}

// AC: Non-loopback non-ts-net peers refused unless --federation-allow-plain-http.
func TestFederationStrictDefaultRefusesPlainHTTP(t *testing.T) {
	s := newHubServer(t, false)
	resp := federationDoRequest(t, s, "POST", "/api/federation/register", goodRegisterPayload("n1"), "external")
	if resp.StatusCode != http.StatusForbidden {
		t.Fatalf("want 403 from non-trusted peer with strict default, got %d", resp.StatusCode)
	}
}

// AC: Plain-HTTP path emits WARN per accepted registration.
func TestFederationPlainHTTPOptOutEmitsWarn(t *testing.T) {
	s := newHubServer(t, true)
	resp := federationDoRequest(t, s, "POST", "/api/federation/register", goodRegisterPayload("n1"), "external")
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("want 200 with allow-plain-http, got %d", resp.StatusCode)
	}
	warnings := s.HubFederationWarnings()
	if len(warnings) != 1 {
		t.Fatalf("want exactly 1 WARN per accepted registration, got %d (%v)", len(warnings), warnings)
	}

	// Second registration of the same spoke should also log WARN.
