		DDxVersion:    "0.42.0",
		SchemaVersion: "1",
		Capabilities:  []string{"beads", "runs"},
		RegisteredAt:  time.Date(2026, 5, 2, 19, 58, 33, 0, time.UTC),
		LastHeartbeat: hb,
		Status:        StatusActive,
