	}

	var wg sync.WaitGroup
	wg.Add(n)
	for i := 0; i < n; i++ {
		i := i
		go func() {
			defer wg.Done()
			r := NewRegistry()
			_ = r.UpsertSpoke(SpokeRecord{
				NodeID:        "node-" + string(rune('a'+i)),
				Name:          "n",
				URL:           "https://x",
				Status:        StatusActive,
				LastHeartbeat: time.Now().UTC(),
			})
			if err := SaveStateTo(path, r); err != nil {
